import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import { Plus, Trash2, Edit, ArrowLeft, Package } from 'lucide-react';

const GestionOfertas = () => {
    const { id: localId } = useParams();
    const navigate = useNavigate();
    const [ofertas, setOfertas] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        cargarOfertas();
    }, [localId]);

    const cargarOfertas = async () => {
        try {
            const data = await api.getOfertasLocal(localId);
            setOfertas(data);
        } catch (e) { console.error(e); }
        setLoading(false);
    };

    const handleEliminar = async (id) => {
        if (window.confirm("¿Borrar esta oferta?")) {
            await api.eliminarOferta(id);
            cargarOfertas();
        }
    };

    return (
        <div style={containerStyle}>
            <button onClick={() => navigate('/dashboard')} style={btnBack}>
                <ArrowLeft size={18}/> Volver al Dashboard
            </button>
            
            <div style={headerStyle}>
                <h2>Gestión de Stock e Inventario</h2>
                <button style={btnPlus}><Plus size={20}/> Agregar Producto</button>
            </div>

            <div style={listStyle}>
                {ofertas.map(o => (
                    <div key={o._id} style={itemStyle}>
                        <img src={o.imagenUrl} alt={o.producto} style={imgStyle} />
                        <div style={{flex:1}}>
                            <h4 style={{margin:0}}>{o.producto}</h4>
                            <p style={precioStyle}>${o.precio}</p>
                        </div>
                        <div style={actionsStyle}>
                            <button style={btnIconEdit}><Edit size={16}/></button>
                            <button onClick={() => handleEliminar(o._id)} style={btnIconDelete}><Trash2 size={16}/></button>
                        </div>
                    </div>
                ))}
                {ofertas.length === 0 && (
                    <div style={emptyState}><Package size={48}/><p>No hay ofertas publicadas aún</p></div>
                )}
            </div>
        </div>
    );
};

// Estilos de la lista
const containerStyle = { padding: '40px', maxWidth: '900px', margin: '0 auto' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '8px' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '15px' };
const itemStyle = { display: 'flex', alignItems: 'center', gap: '20px', padding: '15px', background: 'white', borderRadius: '15px', border: '1px solid #f1f5f9' };
const imgStyle = { width: '60px', height: '60px', borderRadius: '10px', objectFit: 'cover' };
const precioStyle = { color: '#27ae60', fontWeight: 'bold', margin: '5px 0 0 0' };
const actionsStyle = { display: 'flex', gap: '10px' };
const btnIconEdit = { background: '#f1f5f9', border: 'none', padding: '10px', borderRadius: '8px', cursor: 'pointer' };
const btnIconDelete = { background: '#fee2e2', border: 'none', padding: '10px', borderRadius: '8px', cursor: 'pointer', color: '#ef4444' };
const btnPlus = { background: '#1e293b', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };
const emptyState = { textAlign: 'center', padding: '50px', color: '#cbd5e1' };

export default GestionOfertas;
